class Solution {
    public ListNode removeZeroSumSublists(ListNode head) {
        ListNode dummy = new ListNode(0);
        dummy.next = head;
        int[] prefixSum = new int[1001];
        prefixSum[0] = 0;
        int index = 0;
        while (head != null) {
            index++;
            prefixSum[index] = prefixSum[index - 1] + head.val;
            int i = 0;
            while (i < index && prefixSum[i] != prefixSum[index]) {
                i++;
            }
            if (i < index) {
                ListNode node = dummy;
                while (node.next != head) {
                    node = node.next;
                }
                node.next = head.next;
                head = head.next;
            } else {
                head = head.next;
            }
        }
        return dummy.next;
    }
}
